  ('fire-eq-tech-moex-02260', 'fire-eq-tech', 'fire-eq-tech-moex-102-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某餐廳廚房之瓦斯燃燒器具使用液化石油氣為燃料時，依法應於距瓦斯燃燒器具或瓦斯導管貫穿牆壁處 水平距離Ｘ公尺以內、便於檢修處設有瓦斯漏氣檢知器，檢知器上端，裝設在距樓地板面Ｙ公分範圍內， 試問Ｘ、Ｙ分別為何？', '["X＝3、Y＝60", "X＝4、Y＝30", "X＝5、Y＝20", "X＝8、Y＝10"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a28a5fe44378", "answer_pdf_sha1": "079fbe44f242", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
