  ('fire-eq-tech-moex-02269', 'fire-eq-tech', 'fire-eq-tech-moex-102-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '有關避難梯設置之規定，下列敘述何者不正確？', '["4樓以上樓層應設固定梯，設於陽臺等具安全且容易避難逃生構造處，其樓地板面積至少4平方公尺以上", "固定梯的橫桿與使用場所牆面保持10公分以上之距離", "固定梯設於陽臺時，應附設能內接直徑60公分以上之逃生孔", "固定梯之逃生孔應上下層交錯配置，不得在同一直線上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a28a5fe44378", "answer_pdf_sha1": "079fbe44f242", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
